#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 5e4+5;
const int M = N*150;
struct Query{int opt,l,r,x,k;}q[N];
struct Tree{int sum,ls,rs;}t[M];
int n,Q,a[N],num_cnt,bel[2*N];
int node_cnt,Rt[N],tmp[2][N];
map<int,int> Ls;
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void push_up(int u){
    t[u].sum=t[t[u].ls].sum+t[t[u].rs].sum;return;
}
void change(int &u,int l,int r,int p,int k){
    if(!u)u=(++node_cnt);
    if(l==r&&l==p){t[u].sum+=k;return;}
    int mid=(l+r)>>1;
    if(p<=mid)change(t[u].ls,l,mid,p,k);
    else change(t[u].rs,mid+1,r,p,k);
    push_up(u);return;
}
void add(int u,int k){
    int x=a[u];
    while(u<=n)
        change(Rt[u],1,num_cnt,x,k),u+=u&-u;return;
}
int queryNum(int l,int r,int k){
    if(l==r)return l;
    int mid=(l+r)>>1,now=0;
    for(int i=1;i<=tmp[0][0];i++)now+=t[t[tmp[0][i]].ls].sum;
    for(int i=1;i<=tmp[1][0];i++)now-=t[t[tmp[1][i]].ls].sum;
    if(k<=now){
        for(int i=1;i<=tmp[0][0];i++)tmp[0][i]=t[tmp[0][i]].ls;
        for(int i=1;i<=tmp[1][0];i++)tmp[1][i]=t[tmp[1][i]].ls;
        return queryNum(l,mid,k);
    }else{
        for(int i=1;i<=tmp[0][0];i++)tmp[0][i]=t[tmp[0][i]].rs;
        for(int i=1;i<=tmp[1][0];i++)tmp[1][i]=t[tmp[1][i]].rs;
        return queryNum(mid+1,r,k-now);
    }
}
int askNum(int l,int r,int k){
    tmp[0][0]=0,tmp[1][0]=0;l--;
    while(r)tmp[0][++tmp[0][0]]=Rt[r],r-=r&-r;
    while(l)tmp[1][++tmp[1][0]]=Rt[l],l-=l&-l;
    return queryNum(1,num_cnt,k);
}
int queryRank(int l,int r,int k){
    if(l==r)return 0;
    int mid=(l+r)>>1;
    if(k<=mid){
        for(int i=1;i<=tmp[0][0];i++)tmp[0][i]=t[tmp[0][i]].ls;
        for(int i=1;i<=tmp[1][0];i++)tmp[1][i]=t[tmp[1][i]].ls;
        return queryRank(l,mid,k);
    }else{
        int now=0;
        for(int i=1;i<=tmp[0][0];i++)
            now+=t[t[tmp[0][i]].ls].sum,
            tmp[0][i]=t[tmp[0][i]].rs;
        for(int i=1;i<=tmp[1][0];i++)
            now-=t[t[tmp[1][i]].ls].sum,
            tmp[1][i]=t[tmp[1][i]].rs;
        return now+queryRank(mid+1,r,k);
    }
}
int askRank(int l,int r,int k){
    tmp[0][0]=0,tmp[1][0]=0;l--;
    while(r)tmp[0][++tmp[0][0]]=Rt[r],r-=r&-r;
    while(l)tmp[1][++tmp[1][0]]=Rt[l],l-=l&-l;
    return queryRank(1,num_cnt,k)+1;
}
int Find_pre(int l,int r,int k){
    int rk=askRank(l,r,k)-1;
    if(!rk)return 0;
    else return askNum(l,r,rk);
}
int Find_nxt(int l,int r,int k){
    if(k==num_cnt)return num_cnt+1;
    int rk=askRank(l,r,k+1);
    if(rk==r-l+2)return num_cnt+1;
    else return askNum(l,r,rk);
}
int main(){
    n=read(),Q=read();
    for(int i=1;i<=n;i++)a[i]=read(),Ls[a[i]]=0;
    for(int i=1;i<=Q;i++){
        q[i].opt=read();
        if(q[i].opt==3)q[i].x=read(),q[i].k=read();
        else q[i].l=read(),q[i].r=read(),q[i].k=read();
        if(q[i].opt!=2)Ls[q[i].k]=0;
    }for(auto &u:Ls)u.se=(++num_cnt),bel[u.se]=u.fr;
    bel[0]=-2147483647,bel[num_cnt+1]=2147483647;
    for(int i=1;i<=n;i++)a[i]=Ls[a[i]],add(i,1);
    for(int i=1;i<=Q;i++)
        if(q[i].opt!=2)q[i].k=Ls[q[i].k];
    for(int i=1;i<=Q;i++)
        if(q[i].opt==1)cout<<askRank(q[i].l,q[i].r,q[i].k)<<"\n";
        else if(q[i].opt==2)cout<<bel[askNum(q[i].l,q[i].r,q[i].k)]<<"\n";
        else if(q[i].opt==3)add(q[i].x,-1),a[q[i].x]=q[i].k,add(q[i].x,1);
        else if(q[i].opt==4)cout<<bel[Find_pre(q[i].l,q[i].r,q[i].k)]<<"\n";
        else cout<<bel[Find_nxt(q[i].l,q[i].r,q[i].k)]<<"\n";
    return 0;
}
